      arab: "\u0641\u064e\u0630\u064e\u0631\u0652\u0647\u064f\u0645\u0652 \u0641\u0650\u064a \u063a\u064e\u0645\u0652\u0631\u064e\u062a\u0650\u0647\u0650\u0645\u0652 \u062d\u064e\u062a\u0651\u064e\u0649\u0670 \u062d\u0650\u064a\u0646\u064d",
